import React, { useEffect, useMemo, useState } from 'react';
import { Line } from 'react-chartjs-2';
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, Tooltip, Legend, Filler } from 'chart.js';
import { environmentLogService } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import '../../styles/technician/technician-layout.css';
import '../../styles/technician/technician-environment.css';
import { pushToast } from "../../utils/toastBridge";
ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Tooltip, Legend, Filler);
const emptyForm = {
  pondId: '',
  ph: '',
  temperature: '',
  oxygen: '',
  salinity: '',
  turbidity: ''
};
const RANGE_OPTIONS = [{
  value: 1,
  label: '1 ngày'
}, {
  value: 7,
  label: '7 ngày'
}, {
  value: 30,
  label: '30 ngày'
}];
const METRIC_CONFIG = [{
  key: 'ph',
  label: 'pH',
  unit: 'pH',
  color: '#2b7de9'
}, {
  key: 'temperature',
  label: 'Nhi�!t ��"',
  unit: '°C',
  color: '#2fb5ab'
}, {
  key: 'oxygen',
  label: 'DO',
  unit: 'mg/L',
  color: '#4f8edc'
}, {
  key: 'salinity',
  label: 'Đ�" mặn',
  unit: 'ppt',
  color: '#5b9bd5'
}, {
  key: 'turbidity',
  label: 'Đ�" �ục',
  unit: 'NTU',
  color: '#1f87b7'
}];
const formatDateTime = value => {
  if (!value) return '-';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '-';
  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const formatShortTime = value => {
  if (!value) return '--:--';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '--:--';
  return new Intl.DateTimeFormat('vi-VN', {
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
    timeZone: 'Asia/Ho_Chi_Minh'
  }).format(date);
};
const formatNumber = value => {
  if (value === null || value === undefined || value === '') return '-';
  const number = Number(value);
  if (Number.isNaN(number)) return '-';
  return (Math.round(number * 100) / 100).toFixed(2);
};
const formatRelativeTime = value => {
  if (!value) return 'Chưa có dữ li�!u';
  const diffMs = Date.now() - new Date(value).getTime();
  if (diffMs < 0) return 'Vừa xong';
  const minutes = Math.floor(diffMs / 60000);
  if (minutes < 1) return 'Vừa xong';
  if (minutes < 60) return `${minutes} phút trư�:c`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours} giờ trư�:c`;
  const days = Math.floor(hours / 24);
  return `${days} ngày trư�:c`;
};
const toNumber = value => {
  if (value === null || value === undefined || value === '') return null;
  const parsed = Number(value);
  return Number.isNaN(parsed) ? null : parsed;
};
const isOutOfRange = (log, thresholds) => {
  const ph = toNumber(log.ph);
  const temperature = toNumber(log.temperature);
  const oxygen = toNumber(log.oxygen);
  const salinity = toNumber(log.salinity);
  const turbidity = toNumber(log.turbidity);
  const minPh = toNumber(thresholds?.min_ph);
  const maxPh = toNumber(thresholds?.max_ph);
  const minTemp = toNumber(thresholds?.min_temp);
  const maxTemp = toNumber(thresholds?.max_temp);
  const minOxygen = toNumber(thresholds?.min_oxygen);
  const maxOxygen = toNumber(thresholds?.max_oxygen);
  const minSalinity = toNumber(thresholds?.min_salinity);
  const maxSalinity = toNumber(thresholds?.max_salinity);
  const minTurbidity = toNumber(thresholds?.min_turbidity);
  const maxTurbidity = toNumber(thresholds?.max_turbidity);
  const generic = {
    ph: {
      min: 6.5,
      max: 8.5
    },
    temperature: {
      min: 25,
      max: 33
    },
    oxygen: {
      min: 4,
      max: 9
    },
    salinity: {
      min: 0,
      max: 35
    },
    turbidity: {
      min: 0,
      max: 10
    }
  };
  const compare = (value, min, max, fallback) => {
    if (value === null) return false;
    const lower = min ?? fallback.min;
    const upper = max ?? fallback.max;
    return value < lower || value > upper;
  };
  return compare(ph, minPh, maxPh, generic.ph) || compare(temperature, minTemp, maxTemp, generic.temperature) || compare(oxygen, minOxygen, maxOxygen, generic.oxygen) || compare(salinity, minSalinity, maxSalinity, generic.salinity) || compare(turbidity, minTurbidity, maxTurbidity, generic.turbidity);
};
const createMiniChartOptions = () => ({
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: {
      display: false
    },
    tooltip: {
      callbacks: {
        label: context => `${context.parsed.y}`
      }
    }
  },
  elements: {
    point: {
      radius: 0,
      hoverRadius: 3
    },
    line: {
      tension: 0.36,
      borderWidth: 2
    }
  },
  scales: {
    x: {
      display: false
    },
    y: {
      display: false
    }
  },
  interaction: {
    mode: 'index',
    intersect: false
  }
});
const TechnicianEnvironment = () => {
  const {
    user,
    ponds
  } = useAuth();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [environmentLogs, setEnvironmentLogs] = useState([]);
  const [thresholds, setThresholds] = useState(null);
